/*! QRCode helper for POS SaaS — fix18-09F-hotfix1
 *  Uses external QR API with canvas fallback.
 *  No broken minified RS-block code.
 */
(function (global) {
  'use strict';

  /**
   * QRCode(element, options)
   * options: string URL  -or-  { text, width, height }
   */
  global.QRCode = function (el, opts) {
    var url  = typeof opts === 'string' ? opts : (opts && opts.text) || '';
    var size = (opts && opts.width) || 256;

    // Primary: api.qrserver.com  |  Fallback: Google Charts
    var apis = [
      'https://api.qrserver.com/v1/create-qr-code/?size=' + size + 'x' + size + '&data=',
      'https://chart.googleapis.com/chart?chs=' + size + 'x' + size + '&cht=qr&chl='
    ];
    var tried = 0;

    var img = new Image();
    img.crossOrigin = 'anonymous';

    function tryNext() {
      if (tried >= apis.length) {
        el.innerHTML =
          '<div style="text-align:center;padding:12px;word-break:break-all;font-size:12px;color:#333">' +
          '<div style="margin-bottom:8px;font-size:14px;font-weight:bold">📲 掃描連結</div>' +
          '<a href="' + url + '" target="_blank" style="color:#06C755">' + url + '</a>' +
          '</div>';
        return;
      }
      img.onload = function () {
        el.innerHTML = '';
        img.style.cssText =
          'width:' + size + 'px;height:' + size + 'px;' +
          'display:block;margin:0 auto;border-radius:4px;background:#fff';
        el.appendChild(img);
      };
      img.onerror = tryNext;
      img.src = apis[tried++] + encodeURIComponent(url);
    }

    tryNext();

    // Expose for external canvas-download usage
    el._qrImg = img;
    el._qrUrl = url;
  };

  global.QRCode.CorrectLevel = { L: 1, M: 0, Q: 3, H: 2 };

})(typeof window !== 'undefined' ? window : this);
